// Secret Manager returns { payload: { data: '<base64>' } }
const decode = b64 => Buffer.from(b64, 'base64').toString('utf8').trim();

const shopDomain  = decode($('Get shop_domain').first().json.payload.data);
const accessToken = decode($('Get access_token').first().json.payload.data);
const apiVersion  = decode($('Get api_version').first().json.payload.data) || '2025-01';

const client = $('Loop over clients').item.json;

return [{
  json: {
    client_id:    client.client_id,
    slug:         client.slug,
    currency:     client.currency,
    timezone:     client.timezone,
    country:      client.country,
    shop_domain:  shopDomain,
    access_token: accessToken,
    api_version:  apiVersion
  }
}];

const ctx = $('Decode secrets').first().json;
const CLIENT_ID = ctx.client_id;
const INGESTED_AT = new Date().toISOString();
const num = v => (v === null || v === undefined || v === '' ? 0 : Number(v));

// Each input item is one HTTP response with { orders: [...] }.
// Flatten across all paginated responses.
const allOrders = [];
for (const item of $input.all()) {
  const arr = item.json.orders ?? [];
  for (const o of arr) allOrders.push(o);
}

return allOrders.map(o => ({
  json: {
    client_id:             CLIENT_ID,
    ingested_at:           INGESTED_AT,
    ingest_source:         'backfill',

    order_id:              String(o.id),
    order_number:          o.name ?? '',
    order_date:            (o.processed_at || o.created_at || '').slice(0, 10),
    created_at:            o.created_at || null,
    updated_at:            o.updated_at || null,
    processed_at:          o.processed_at || null,

    currency:              o.currency || '',
    presentment_currency:  o.presentment_currency || o.currency || '',
    subtotal_price:        num(o.subtotal_price),
    total_shipping:        num(o.total_shipping_price_set?.shop_money?.amount),
    total_tax:             num(o.total_tax),
    total_discounts:       num(o.total_discounts),
    total_price:           num(o.total_price),

    customer_id:           String(o.customer?.id ?? ''),
    customer_email:        o.customer?.email ?? o.email ?? '',
    is_returning_customer: Boolean((o.customer?.orders_count ?? 0) > 1),
    shipping_country:      o.shipping_address?.country_code ?? '',
    shipping_province:     o.shipping_address?.province_code ?? '',

    financial_status:      o.financial_status ?? '',
    fulfillment_status:    o.fulfillment_status ?? '',
    cancelled_at:          o.cancelled_at || null,
    source_name:           o.source_name ?? '',

    line_items: (o.line_items ?? []).map(li => ({
      line_item_id:       String(li.id),
      product_id:         String(li.product_id ?? ''),
      variant_id:         String(li.variant_id ?? ''),
      sku:                li.sku ?? '',
      title:              li.title ?? '',
      quantity:           num(li.quantity),
      price:              num(li.price),
      total_discount:     num(li.total_discount),
      fulfillment_status: li.fulfillment_status ?? null
    })),

    payload_json:          JSON.stringify(o)
  }
}));
